# @cctt_verify {"v":2,"sym":"sympy.vector.tests.test_field_functions.test_scalar_potential_difference","kind":"function","src_hash":"49920fe48e4b06be","in":{"base":"Any"},"out":{"base":"Any","pred":"scalar_potential_difference(S.Zero, C, point1, point2) == 0 and scalar_potential_difference(grad_field, C, point1, point2) == 948"},"spec":{"lhs":"test_scalar_potential_difference()","rhs":"test_scalar_potential_difference produces the expected output","over":{"base":"Any"},"name":"test_scalar_potential_difference_correct"},"guarantee":"test_scalar_potential_difference produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.vector.tests.test_field_functions.test_scalar_potential_difference_correct","statement":"Path(test_scalar_potential_difference(x), test_scalar_potential_difference produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"9b450717cd712b05"}
def test_scalar_potential_difference():
    point1 = C.origin.locate_new('P1', 1*i + 2*j + 3*k)
    point2 = C.origin.locate_new('P2', 4*i + 5*j + 6*k)
    genericpointC = C.origin.locate_new('RP', x*i + y*j + z*k)
    genericpointP = P.origin.locate_new('PP', P.x*P.i + P.y*P.j + P.z*P.k)
    assert scalar_potential_difference(S.Zero, C, point1, point2) == 0
    assert (scalar_potential_difference(scalar_field, C, C.origin,
                                        genericpointC) ==
            scalar_field)
    assert (scalar_potential_difference(grad_field, C, C.origin,
                                        genericpointC) ==
            scalar_field)
    assert scalar_potential_difference(grad_field, C, point1, point2) == 948
    assert (scalar_potential_difference(y*z*i + x*z*j +
                                        x*y*k, C, point1,
                                        genericpointC) ==
            x*y*z - 6)
    potential_diff_P = (2*P.z*(P.x*sin(q) + P.y*cos(q))*
                        (P.x*cos(q) - P.y*sin(q))**2)
    assert (scalar_potential_difference(grad_field, P, P.origin,
                                        genericpointP).simplify() ==
            potential_diff_P.simplify())


